    "cmpx.c6Simy": "Tumbuh sendiri makin sering dipakai",
    "cmpx.c6Ai": "Tergantung data kamu",
    "cmpx.c6Pc": "Tergantung prompt kamu",
    "cmpx.c6Code": "Tergantung engineer",
    "cmpx.c6Cow": "Tergantung aktivitas tim",
    "cmpx.c7": "Cocok untuk",
    "cmpx.c7Simy": "Semua peran bisnis",
    "cmpx.c7Ai": "Siapa pun yang perlu search",
